import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import BookingForm from '../components/BookingForm';
import { MapPin, Wifi, Car, Coffee } from 'lucide-react';

const PropertyDetails = () => {
    const { id } = useParams();
    const [property, setProperty] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Fetch property details
        const fetchProperty = async () => {
            try {
                const response = await fetch(`http://localhost:3001/api/properties/${id}`);
                if (response.ok) {
                    const data = await response.json();
                    setProperty(data);
                } else {
                    // Mock data fallback
                    setProperty({
                        id: id,
                        title: 'Luxury Villa with Ocean View',
                        description: 'Experience the ultimate luxury in this stunning villa overlooking the ocean. Featuring 4 bedrooms, a private pool, and direct beach access.',
                        location: 'Goa, India',
                        pricePerNight: 15000,
                        rating: 4.8,
                        maxGuests: 8,
                        images: ['https://images.unsplash.com/photo-1613490493576-7fde63acd811?ixlib=rb-4.0.3&auto=format&fit=crop&w=1171&q=80'],
                        amenities: ['Wifi', 'Pool', 'Parking', 'AC']
                    });
                }
            } catch (error) {
                console.error('Error fetching property:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchProperty();
    }, [id]);

    if (loading) return <div className="text-center py-10">Loading...</div>;
    if (!property) return <div className="text-center py-10">Property not found</div>;

    return (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
            {/* Title and Location */}
            <div className="mb-6">
                <h1 className="text-3xl font-bold text-gray-900 mb-2">{property.title}</h1>
                <div className="flex items-center gap-2 text-gray-600">
                    <MapPin className="w-5 h-5" />
                    <span>{property.location}</span>
                </div>
            </div>

            {/* Image Gallery (Simplified) */}
            <div className="rounded-2xl overflow-hidden aspect-[2/1] mb-8 relative">
                <img
                    src={property.images?.[0]}
                    alt={property.title}
                    className="w-full h-full object-cover"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                {/* Main Content */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Description */}
                    <div>
                        <h2 className="text-2xl font-semibold mb-4">About this place</h2>
                        <p className="text-gray-600 leading-relaxed">{property.description}</p>
                    </div>

                    {/* Amenities */}
                    <div className="border-t border-gray-200 pt-8">
                        <h2 className="text-2xl font-semibold mb-4">What this place offers</h2>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="flex items-center gap-3 text-gray-600">
                                <Wifi className="w-6 h-6" />
                                <span>Fast Wifi</span>
                            </div>
                            <div className="flex items-center gap-3 text-gray-600">
                                <Car className="w-6 h-6" />
                                <span>Free parking</span>
                            </div>
                            {/* Add more based on property.amenities */}
                        </div>
                    </div>
                </div>

                {/* Booking Sidebar */}
                <div>
                    <BookingForm property={property} onBook={(data) => console.log('Booking:', data)} />
                </div>
            </div>
        </div>
    );
};

export default PropertyDetails;
